@namespace Lumeo

@if (Label is not null && !InsideFormField)
{
    <label class="text-sm font-medium leading-none">
        @Label
        @if (Required)
        {
            <span class="text-destructive ml-0.5">*</span>
        }
    </label>
}

@if (Variant == TimePickerVariant.Wheel)
{
    @* iOS-style wheel picker — hours + minutes (+ AM/PM if 12-hour).
       Seconds are not supported in the wheel variant. *@
    <TimeWheelPicker Value="@Value" ValueChanged="HandleWheelChanged"
                     Use24Hour="@Use24Hour" MinuteStep="@MinuteStep"
                     Culture="@Culture" Class="@Class" />
}
else
{
<Popover @bind-Open="_isOpen">
    <PopoverTrigger>
        <button type="button"
                name="@Name"
                aria-required="@Required.ToString().ToLower()"
                aria-invalid="@EffectiveInvalid.ToString().ToLower()"
                class="@CssClass"
                disabled="@Disabled"
                @attributes="AdditionalAttributes">
            <Blazicon Svg="Lucide.Clock" class="mr-2 h-4 w-4 shrink-0" />
            @if (Value.HasValue)
            {
                <span>@FormatTime(Value.Value)</span>
            }
            else
            {
                <span class="text-muted-foreground group-hover:text-accent-foreground">@EffectivePlaceholder</span>
            }
        </button>
    </PopoverTrigger>
    <PopoverContent Align="Lumeo.Align.Start" Class="w-auto p-0">
        <div class="flex divide-x divide-border/40">
            @* Hours column *@
            <div class="flex flex-col h-[200px] overflow-y-auto py-1 scrollbar-thin">
                @foreach (var hour in GetHours())
                {
                    var h = hour;
                    var isSelected = Value.HasValue && GetDisplayHour(Value.Value) == h;
                    <button type="button"
                            class="@(isSelected ? "px-3 py-1.5 text-sm cursor-pointer bg-primary text-primary-foreground" : "px-3 py-1.5 text-sm cursor-pointer hover:bg-muted/50 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:bg-muted/50")"
                            @onclick="() => SelectHour(h)">
                        @h.ToString("D2")
                    </button>
                }
            </div>

            @* Minutes column *@
            <div class="flex flex-col h-[200px] overflow-y-auto py-1 scrollbar-thin">
                @foreach (var minute in GetMinutes())
                {
                    var m = minute;
                    var isSelected = Value.HasValue && Value.Value.Minutes == m;
                    <button type="button"
                            class="@(isSelected ? "px-3 py-1.5 text-sm cursor-pointer bg-primary text-primary-foreground" : "px-3 py-1.5 text-sm cursor-pointer hover:bg-muted/50 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:bg-muted/50")"
                            @onclick="() => SelectMinute(m)">
                        @m.ToString("D2")
                    </button>
                }
            </div>

            @* Seconds column *@
            @if (ShowSeconds)
            {
                <div class="flex flex-col h-[200px] overflow-y-auto py-1 scrollbar-thin">
                    @foreach (var second in GetSeconds())
                    {
                        var s = second;
                        var isSelected = Value.HasValue && Value.Value.Seconds == s;
                        <button type="button"
                                class="@(isSelected ? "px-3 py-1.5 text-sm cursor-pointer bg-primary text-primary-foreground" : "px-3 py-1.5 text-sm cursor-pointer hover:bg-muted/50 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:bg-muted/50")"
                                @onclick="() => SelectSecond(s)">
                            @s.ToString("D2")
                        </button>
                    }
                </div>
            }

            @* AM/PM column *@
            @if (!EffectiveUse24Hour)
            {
                <div class="flex flex-col py-1">
                    @{
                        var isAm = !Value.HasValue || Value.Value.Hours < 12;
                        var amLabel = string.IsNullOrEmpty(EffectiveCulture.DateTimeFormat.AMDesignator) ? "AM" : EffectiveCulture.DateTimeFormat.AMDesignator;
                        var pmLabel = string.IsNullOrEmpty(EffectiveCulture.DateTimeFormat.PMDesignator) ? "PM" : EffectiveCulture.DateTimeFormat.PMDesignator;
                    }
                    <button type="button"
                            class="@(isAm ? "px-3 py-1.5 text-sm cursor-pointer bg-primary text-primary-foreground" : "px-3 py-1.5 text-sm cursor-pointer hover:bg-muted/50 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:bg-muted/50")"
                            @onclick="() => SelectAmPm(true)">
                        @amLabel
                    </button>
                    <button type="button"
                            class="@(!isAm ? "px-3 py-1.5 text-sm cursor-pointer bg-primary text-primary-foreground" : "px-3 py-1.5 text-sm cursor-pointer hover:bg-muted/50 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:bg-muted/50")"
                            @onclick="() => SelectAmPm(false)">
                        @pmLabel
                    </button>
                </div>
            }
        </div>
    </PopoverContent>
</Popover>
}

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground">@HelperText</p>
    }
}

@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    /// <summary>
    /// Visual style of the picker. <see cref="TimePickerVariant.List"/> renders the
    /// existing scrollable hour/minute columns inside a popover (default).
    /// <see cref="TimePickerVariant.Wheel"/> renders inline iOS-style snap-scrolling
    /// columns. The Wheel variant doesn't show seconds.
    /// </summary>
    public enum TimePickerVariant { List, Wheel }

    [Parameter] public TimePickerVariant Variant { get; set; } = TimePickerVariant.List;

    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    [Parameter] public TimeSpan? Value { get; set; }
    [Parameter] public EventCallback<TimeSpan?> ValueChanged { get; set; }
    /// <summary>
    /// When <c>true</c> renders a 24-hour clock; when <c>false</c> renders 12-hour with AM/PM.
    /// When <c>null</c> (default) the picker derives the choice from
    /// <see cref="EffectiveCulture"/>'s <c>ShortTimePattern</c> — <c>de-DE</c>, <c>fr-FR</c>
    /// and similar see 24-hour; <c>en-US</c> sees 12-hour.
    /// </summary>
    [Parameter] public bool? Use24Hour { get; set; }
    [Parameter] public bool ShowSeconds { get; set; }
    [Parameter] public int MinuteStep { get; set; } = 1;
    [Parameter] public int SecondStep { get; set; } = 1;
    [Parameter] public string? Placeholder { get; set; }

    /// <summary>
    /// Overrides <see cref="System.Globalization.CultureInfo.CurrentCulture"/> for
    /// 24h/12h detection and AM/PM designators. Leave null to honour ASP.NET request localization.
    /// </summary>
    [Parameter] public System.Globalization.CultureInfo? Culture { get; set; }

    private System.Globalization.CultureInfo EffectiveCulture => Culture ?? System.Globalization.CultureInfo.CurrentCulture;
    // Per CLDR/.NET conventions a lowercase "h" in the short-time pattern means 12-hour;
    // uppercase "H" means 24-hour. We honour an explicit Use24Hour first, then derive.
    private bool EffectiveUse24Hour => Use24Hour ?? !EffectiveCulture.DateTimeFormat.ShortTimePattern.Contains('h');

    private string EffectivePlaceholder => Placeholder ?? L["TimePicker.Placeholder"];
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _isOpen;

    private string CssClass => $"group flex h-9 items-center rounded-md border {(EffectiveInvalid ? "border-destructive ring-1 ring-destructive/20" : "border-input")} bg-transparent px-3 py-2 text-sm shadow-sm hover:bg-accent hover:text-accent-foreground disabled:cursor-not-allowed disabled:opacity-50 {Class}".Trim();

    private string FormatTime(TimeSpan time)
    {
        if (EffectiveUse24Hour)
        {
            return ShowSeconds
                ? $"{time.Hours:D2}:{time.Minutes:D2}:{time.Seconds:D2}"
                : $"{time.Hours:D2}:{time.Minutes:D2}";
        }
        else
        {
            var hour12 = time.Hours % 12;
            if (hour12 == 0) hour12 = 12;
            var dtf = EffectiveCulture.DateTimeFormat;
            var ampm = time.Hours < 12
                ? (string.IsNullOrEmpty(dtf.AMDesignator) ? "AM" : dtf.AMDesignator)
                : (string.IsNullOrEmpty(dtf.PMDesignator) ? "PM" : dtf.PMDesignator);
            return ShowSeconds
                ? $"{hour12:D2}:{time.Minutes:D2}:{time.Seconds:D2} {ampm}"
                : $"{hour12:D2}:{time.Minutes:D2} {ampm}";
        }
    }

    private List<int> GetHours()
    {
        var hours = new List<int>();
        if (EffectiveUse24Hour)
        {
            for (var i = 0; i < 24; i++) hours.Add(i);
        }
        else
        {
            for (var i = 1; i <= 12; i++) hours.Add(i);
        }
        return hours;
    }

    private int GetDisplayHour(TimeSpan time)
    {
        if (EffectiveUse24Hour) return time.Hours;
        var h = time.Hours % 12;
        return h == 0 ? 12 : h;
    }

    private List<int> GetMinutes()
    {
        var minutes = new List<int>();
        var step = Math.Max(1, MinuteStep);
        for (var i = 0; i < 60; i += step) minutes.Add(i);
        return minutes;
    }

    private List<int> GetSeconds()
    {
        var seconds = new List<int>();
        var step = Math.Max(1, SecondStep);
        for (var i = 0; i < 60; i += step) seconds.Add(i);
        return seconds;
    }

    private async Task SelectHour(int hour)
    {
        var current = Value ?? TimeSpan.Zero;
        int actualHour;
        if (EffectiveUse24Hour)
        {
            actualHour = hour;
        }
        else
        {
            var isPm = current.Hours >= 12;
            actualHour = hour % 12;
            if (isPm) actualHour += 12;
        }
        var newValue = new TimeSpan(actualHour, current.Minutes, current.Seconds);
        Value = newValue;
        await ValueChanged.InvokeAsync(newValue);
    }

    private async Task SelectMinute(int minute)
    {
        var current = Value ?? TimeSpan.Zero;
        var newValue = new TimeSpan(current.Hours, minute, current.Seconds);
        Value = newValue;
        await ValueChanged.InvokeAsync(newValue);
    }

    private async Task SelectSecond(int second)
    {
        var current = Value ?? TimeSpan.Zero;
        var newValue = new TimeSpan(current.Hours, current.Minutes, second);
        Value = newValue;
        await ValueChanged.InvokeAsync(newValue);
    }

    private async Task HandleWheelChanged(TimeSpan? newValue)
    {
        Value = newValue;
        await ValueChanged.InvokeAsync(newValue);
    }

    private async Task SelectAmPm(bool isAm)
    {
        var current = Value ?? TimeSpan.Zero;
        var hour = current.Hours % 12;
        if (!isAm) hour += 12;
        var newValue = new TimeSpan(hour, current.Minutes, current.Seconds);
        Value = newValue;
        await ValueChanged.InvokeAsync(newValue);
    }
}

@namespace Lumeo
@using System.Globalization
@using Lumeo.Internal
@implements IDisposable

<div class="@RootCssClass" @attributes="AdditionalAttributes" style="@RootStyle">
    @* Center selection indicator *@
    <div class="absolute left-0 right-0 top-1/2 -translate-y-1/2 h-10 border-y border-primary/30 pointer-events-none"></div>

    @* Hours column *@
    <div class="flex-1 overflow-y-scroll snap-y snap-mandatory scrollbar-none h-full"
         @onscroll="OnHourScroll"
         @ref="_hourCol">
        <div class="h-[60px]"></div>
        @foreach (var h in _hours)
        {
            var hour = h;
            <div class="h-10 flex items-center justify-center snap-center text-base select-none @(hour == _hour ? "text-primary font-semibold" : "text-muted-foreground")">
                @hour.ToString("D2")
            </div>
        }
        <div class="h-[60px]"></div>
    </div>

    @* Minutes column *@
    <div class="flex-1 overflow-y-scroll snap-y snap-mandatory scrollbar-none h-full"
         @onscroll="OnMinuteScroll"
         @ref="_minuteCol">
        <div class="h-[60px]"></div>
        @foreach (var m in _minutes)
        {
            var minute = m;
            <div class="h-10 flex items-center justify-center snap-center text-base select-none @(minute == _minute ? "text-primary font-semibold" : "text-muted-foreground")">
                @minute.ToString("D2")
            </div>
        }
        <div class="h-[60px]"></div>
    </div>

    @* AM/PM column (12-hour only) *@
    @if (!EffectiveUse24Hour)
    {
        <div class="flex-1 overflow-y-scroll snap-y snap-mandatory scrollbar-none h-full"
             @onscroll="OnPeriodScroll"
             @ref="_periodCol">
            <div class="h-[60px]"></div>
            @for (var p = 0; p < 2; p++)
            {
                var period = p;
                var label = period == 0 ? _amLabel : _pmLabel;
                <div class="h-10 flex items-center justify-center snap-center text-base select-none @(period == _periodIndex ? "text-primary font-semibold" : "text-muted-foreground")">
                    @label
                </div>
            }
            <div class="h-[60px]"></div>
        </div>
    }
</div>

@inject Lumeo.Services.IComponentInteropService Interop

@code {
    // --- Public API ----------------------------------------------------------
    [Parameter] public TimeSpan? Value { get; set; }
    [Parameter] public EventCallback<TimeSpan?> ValueChanged { get; set; }
    /// <summary>
    /// When <c>true</c> renders a 24-hour clock; when <c>false</c> renders 12-hour with AM/PM.
    /// When <c>null</c> (default), derived from <see cref="CultureInfo.DateTimeFormat.ShortTimePattern"/>.
    /// </summary>
    [Parameter] public bool? Use24Hour { get; set; }
    [Parameter] public int MinuteStep { get; set; } = 1;
    [Parameter] public CultureInfo? Culture { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // --- Layout constants ----------------------------------------------------
    private const int ItemHeight = 40;
    private const int Height = 160;

    // --- Element refs --------------------------------------------------------
    private ElementReference _hourCol;
    private ElementReference _minuteCol;
    private ElementReference _periodCol;

    // --- Selection state -----------------------------------------------------
    private int _hour = 0;           // display hour (0-23 or 1-12)
    private int _minute = 0;
    private int _periodIndex = 0;    // 0=AM, 1=PM (only relevant when !Use24Hour)
    private List<int> _hours = new();
    private List<int> _minutes = new();
    private string _amLabel = "AM";
    private string _pmLabel = "PM";

    private const int SnapDebounceMs = 100;
    private readonly DebouncedValue<int> _hourDebounced = new(SnapDebounceMs);
    private readonly DebouncedValue<int> _minuteDebounced = new(SnapDebounceMs);
    private readonly DebouncedValue<int> _periodDebounced = new(SnapDebounceMs);
    private bool _initialised;

    private CultureInfo EffectiveCulture => Culture ?? CultureInfo.CurrentCulture;
    // Mirror TimePicker's derivation: lowercase "h" in ShortTimePattern = 12-hour.
    private bool EffectiveUse24Hour => Use24Hour ?? !EffectiveCulture.DateTimeFormat.ShortTimePattern.Contains('h');

    private string RootCssClass => $"flex gap-2 relative {Class}".Trim();
    private string RootStyle => $"height: {Height}px;";

    protected override void OnParametersSet()
    {
        var dtf = EffectiveCulture.DateTimeFormat;
        _amLabel = string.IsNullOrEmpty(dtf.AMDesignator) ? "AM" : dtf.AMDesignator;
        _pmLabel = string.IsNullOrEmpty(dtf.PMDesignator) ? "PM" : dtf.PMDesignator;

        _hours = EffectiveUse24Hour
            ? Enumerable.Range(0, 24).ToList()
            : Enumerable.Range(1, 12).ToList();

        var step = Math.Max(1, MinuteStep);
        _minutes = new List<int>();
        for (var i = 0; i < 60; i += step) _minutes.Add(i);

        var seed = Value ?? TimeSpan.Zero;
        if (EffectiveUse24Hour)
        {
            _hour = seed.Hours;
        }
        else
        {
            var h12 = seed.Hours % 12;
            _hour = h12 == 0 ? 12 : h12;
            _periodIndex = seed.Hours >= 12 ? 1 : 0;
        }
        // Snap the seeded minute to the closest step.
        _minute = SnapMinute(seed.Minutes);
    }

    private int SnapMinute(int minute)
    {
        if (_minutes.Count == 0) return 0;
        var nearest = _minutes[0];
        var bestDiff = Math.Abs(minute - nearest);
        foreach (var m in _minutes)
        {
            var d = Math.Abs(minute - m);
            if (d < bestDiff) { bestDiff = d; nearest = m; }
        }
        return nearest;
    }

    // --- Scroll handlers -----------------------------------------------------
    private async Task OnHourScroll()
    {
        if (!_initialised) return;
        var idx = await GetIndexAsync(_hourCol);
        if (idx < 0 || idx >= _hours.Count) return;
        _hourDebounced.Set(_hours[idx]);
    }

    private async Task OnMinuteScroll()
    {
        if (!_initialised) return;
        var idx = await GetIndexAsync(_minuteCol);
        if (idx < 0 || idx >= _minutes.Count) return;
        _minuteDebounced.Set(_minutes[idx]);
    }

    private async Task OnPeriodScroll()
    {
        if (!_initialised) return;
        var idx = await GetIndexAsync(_periodCol);
        if (idx < 0 || idx > 1) return;
        _periodDebounced.Set(idx);
    }

    private async Task<int> GetIndexAsync(ElementReference el)
    {
        var scrollTop = await Interop.WheelScrollTop(el);
        return (int)Math.Round(scrollTop / ItemHeight);
    }

    protected override void OnInitialized()
    {
        _hourDebounced.OnChanged(pending => InvokeAsync(async () =>
        {
            if (pending == _hour) return;
            _hour = pending;
            await RaiseChange();
            StateHasChanged();
        }));
        _minuteDebounced.OnChanged(pending => InvokeAsync(async () =>
        {
            if (pending == _minute) return;
            _minute = pending;
            await RaiseChange();
            StateHasChanged();
        }));
        _periodDebounced.OnChanged(pending => InvokeAsync(async () =>
        {
            if (pending == _periodIndex) return;
            _periodIndex = pending;
            await RaiseChange();
            StateHasChanged();
        }));
    }

    private async Task RaiseChange()
    {
        int hour24;
        if (EffectiveUse24Hour)
        {
            hour24 = _hour;
        }
        else
        {
            var h = _hour % 12;
            hour24 = _periodIndex == 1 ? h + 12 : h;
        }
        var t = new TimeSpan(hour24, _minute, 0);
        await ValueChanged.InvokeAsync(t);
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            var hourIdx = _hours.IndexOf(_hour);
            if (hourIdx >= 0) await Interop.WheelScrollTo(_hourCol, hourIdx * ItemHeight);

            var minuteIdx = _minutes.IndexOf(_minute);
            if (minuteIdx >= 0) await Interop.WheelScrollTo(_minuteCol, minuteIdx * ItemHeight);

            if (!EffectiveUse24Hour)
            {
                await Interop.WheelScrollTo(_periodCol, _periodIndex * ItemHeight);
            }

            // 2.2.3: was Task.Delay().ContinueWith(...) — see DateWheelPicker
            // for the rationale. Moves the continuation onto the Blazor sync
            // context so exceptions are observed, not lost on the thread pool.
            _ = InvokeAsync(async () =>
            {
                try
                {
                    await Task.Delay(150);
                    _initialised = true;
                }
                catch (JSDisconnectedException) { /* circuit teardown — fine */ }
            });
        }
    }

    public void Dispose()
    {
        _hourDebounced.Dispose();
        _minuteDebounced.Dispose();
        _periodDebounced.Dispose();
    }
}
